before_code:
library ieee;
use ieee.std_logic_1164.all;

entity priority_encoder is
  port (
    req_a, req_b, req_c, req_d : in std_logic;
    grant : out std_logic_vector(1 downto 0)
  );
end entity;

architecture rtl of priority_encoder is
begin
  process(req_a) is
  begin
    if req_a = '1' then
      grant <= "00";
    elsif req_b = '1' then
      grant <= "01";
    elsif req_c = '1' then
      grant <= "10";
    elsif req_d = '1' then
      grant <= "11";
    else
      grant <= "00";
    end if;
  end process;
end architecture;

